<script>

// ── TOAST ──
function showToast(msg) {
  const el = document.createElement('div');
  var bg = 'rgba(255,80,80,.9)'; // 默认红色（错误）
  if (msg.indexOf('✅') === 0) bg = 'rgba(80,180,100,.9)'; // ✅ 绿色（成功）
  else if (msg.indexOf('❓') === 0) bg = 'rgba(100,160,220,.9)'; // ❓ 蓝色（提示）
  el.style.cssText = 'position:fixed;bottom:30px;left:50%;transform:translateX(-50%);background:'+bg+';color:#fff;padding:10px 24px;border-radius:30px;font-size:14px;z-index:999;animation:fadeUp .3s;backdrop-filter:blur(8px)';
  el.textContent = msg;
  document.body.appendChild(el);
  setTimeout(() => el.remove(), 3000);
}

// ── NAV SCROLL ──
const nav = document.getElementById('navbar');
window.addEventListener('scroll', function(){
  nav.classList.toggle('scrolled', window.scrollY > 60);
  let fs = document.querySelectorAll('.fade-up');
  let wh = window.innerHeight;
  fs.forEach(el => {
    let rect = el.getBoundingClientRect();
    if(rect.top < wh - 100) el.classList.add('visible');
  });
});

// ── COUNTER ANIMATION ──
function animateCounters() {
  document.querySelectorAll('[data-count]').forEach(el => {
    let target = parseInt(el.getAttribute('data-count'));
    let current = 0;
    let step = Math.ceil(target / 50);
    let interval = setInterval(() => {
      current += step;
      if(current >= target) { current = target; clearInterval(interval); }
      el.textContent = current;
    }, 30);
  });
}
setTimeout(animateCounters, 800);

// ── PARTICLES ──
const canvas = document.getElementById('particles');
const ctx = canvas.getContext('2d');
let particles = [];
function resizeCanvas() { canvas.width = window.innerWidth; canvas.height = window.innerHeight; }
resizeCanvas(); window.addEventListener('resize', resizeCanvas);

class Particle {
  constructor(){ this.reset(); }
  reset(){
    this.x = Math.random() * canvas.width;
    this.y = Math.random() * canvas.height;
    this.size = Math.random() * 2 + .3;
    this.speedX = (Math.random() - .5) * .4;
    this.speedY = (Math.random() - .5) * .4;
    this.opacity = Math.random() * .4 + .1;
  }
  update(){
    this.x += this.speedX; this.y += this.speedY;
    if(this.x < 0 || this.x > canvas.width || this.y < 0 || this.y > canvas.height) this.reset();
  }
  draw(){
    ctx.beginPath(); ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(100,180,255,' + this.opacity + ')';
    ctx.fill();
  }
}
for(let i = 0; i < 80; i++) particles.push(new Particle());

function drawParticles(){
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  particles.forEach(p => { p.update(); p.draw(); });
  // Connect nearby particles
  for(let i = 0; i < particles.length; i++){
    for(let j = i + 1; j < particles.length; j++){
      let dx = particles[i].x - particles[j].x;
      let dy = particles[i].y - particles[j].y;
      let dist = Math.sqrt(dx * dx + dy * dy);
      if(dist < 150){
        ctx.beginPath();
        ctx.moveTo(particles[i].x, particles[i].y);
        ctx.lineTo(particles[j].x, particles[j].y);
        ctx.strokeStyle = 'rgba(100,180,255,' + (.06 * (1 - dist/150)) + ')';
        ctx.stroke();
      }
    }
  }
  requestAnimationFrame(drawParticles);
}
drawParticles();

