const resultPanel = document.getElementById('resultPanel');
const detectPlaceholder = document.getElementById('detectPlaceholder');
const scoreNum = document.getElementById('scoreNum');
const scoreCircle = document.getElementById('scoreCircle');
const hairType = document.getElementById('hairType');
const summary = document.getElementById('summary');
const tipsContainer = document.getElementById('tipsContainer');
const resetBtn = document.getElementById('resetBtn');

const steps = ['发质AI检测中...', '识别头发区域', '分析发质状态...', '评估毛囊密度...', '检测头皮环境...', '生成综合报告...', '匹配护理方案...'];

uploadZone.addEventListener('click', () => fileInput.click());
fileInput.addEventListener('change', (e) => {
  if(e.target.files.length) startScan(e.target.files[0]);
});
uploadZone.addEventListener('dragover', (e) => { e.preventDefault(); uploadZone.classList.add('dragover'); });
uploadZone.addEventListener('dragleave', () => uploadZone.classList.remove('dragover'));
uploadZone.addEventListener('drop', (e) => { e.preventDefault(); uploadZone.classList.remove('dragover'); if(e.dataTransfer.files.length) startScan(e.dataTransfer.files[0]); });

retryBtn.addEventListener('click', (e) => { e.stopPropagation(); resetDetect(); });
resetBtn.addEventListener('click', resetDetect);

function startScan(file){
  if(file.type.indexOf('image/') !== 0) return alert('请选择图片文件');
  // 检查图片尺寸
  const imgCheck = new Image();
  imgCheck.onload = function() {
    if (this.width < 20 || this.height < 20) {
      showToast('图片太小（至少20x20像素），请上传清晰的头皮照片');
      return;
    }
    preview.src = this.src;
    preview.style.display = 'block';
    uploadZone.classList.add('has-image');
    resultPanel.classList.remove('active');
    detectPlaceholder.style.display = 'none';
    runScan();
  };
  imgCheck.onerror = function() {
    showToast('图片加载失败，请重新选择');
  };
  const reader = new FileReader();
  reader.onload = (e) => { imgCheck.src = e.target.result; };
  reader.readAsDataURL(file);
}function runScan(){
  scanOverlay.classList.add('active');
  scanProgressBar.style.width = '0%';
  let i = 0;
  const totalTime = 2500;
  const interval = totalTime / steps.length;
  scanSteps.textContent = steps[0];
  const timer = setInterval(() => {
    i++;
    if(i >= steps.length) {
      clearInterval(timer);
      scanOverlay.classList.remove('active');
      // Call real AI API
      callAI();
      return;
    }
    scanSteps.textContent = steps[i];
    scanProgressBar.style.width = Math.round((i / (steps.length - 1)) * 100) + '%';
  }, interval);
}

async function callAI(){
  const imgData = preview.src;
  try {
    const resp = await fetch(API_BASE + '/api/detect', {
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({image: imgData})
    });
    // 安全检查：如果返回的不是 JSON（例如 Pages Function fallback 返回了 HTML），直接提示并退出
    const ct = (resp.headers.get('content-type') || '').toLowerCase();
    if (!ct.includes('json')) {
      showToast('服务暂不可用，请刷新后重试');
      resetDetect();
      return;
    }
    const data = await resp.json();
    if(data.code !== 0) {
      // 显示具体错误（如：上传的不是头皮照片）
      showToast((data.message || '检测失败') + '，请重新上传');
      // 还原上传状态
      resetDetect();
      return;
    }
    // data.data = record { id, userId, image, result, recommendedProducts, ... }
    // 提取 result 字段给前端渲染
    const detectRecord = data.data;
    showResult(detectRecord.result || detectRecord);
  } catch(e) {
    showToast('AI服务暂不可用，请稍后再试');
    resetDetect();
  }
}

