/** 获取当前检测报告数据（从界面元素读取） */
function getCurrentReportStats() {
  const scoreText = document.getElementById('scoreNum')?.textContent || '85';
  const score = parseInt(scoreText) || 85;
  const type = document.getElementById('hairType')?.textContent || '健康头皮';
  const summary = document.getElementById('summary')?.textContent || '';
  // 获取四维度评分
  const dims = ['dl1','dl2','dl3','dl4'];
  const dimVals = ['ds1','ds2','ds3','ds4'];
  const dimensions = dims.map((id,i) => ({
    label: document.getElementById(id)?.textContent || '',
    score: parseInt(document.getElementById(dimVals[i])?.textContent) || 0,
  }));
  // 获取护理建议
  const tips = Array.from(document.querySelectorAll('#tipsContainer .tip-text')).map(el => el.textContent).filter(Boolean);
  return { score, type, summary, dimensions, tips };
}

/** 根据分数获取称号、徽章和击败百分比 */
