    color: '#64c882', dimColor: '#45a865', bgTop: '#0a1a12', bgBot: '#0d0d1a',
    glow: 'rgba(100,200,130,0.12)', accent: 'rgba(100,200,130,0.3)',
    desc: '头皮状态优秀，日常护理很到位！',
