// ═══ 分享海报生成 ═══

const shareCardBtn = document.getElementById('shareCardBtn');
const challengeBtn = document.getElementById('challengeBtn');
const posterModal = document.getElementById('posterModal');
const posterPreview = document.getElementById('posterPreview');
const posterDownloadBtn = document.getElementById('posterDownload');

    
    
  document.getElementById('posterModalBg')?.addEventListener('click', closePoster);
  document.getElementById('posterClose')?.addEventListener('click', closePoster);
  posterDownloadBtn?.addEventListener('click', downloadPoster);

async function generatePoster() {
  try {

    const stats = getCurrentReportStats();
    if (!stats || !stats.score) { showToast('\u8bf7\u5148\u5b8c\u6210\u68c0\u6d4b'); return null; }
    const rank = getRankInfo(stats.score);

    const cv = document.getElementById('posterCanvas');
    const ctx = cv.getContext('2d');
    const W = 540, H = 1000, cx = W / 2;
    const F = "'PingFang SC','Microsoft YaHei','Noto Sans SC','Source Han Sans CN',sans-serif";

    // 背景
    var g = ctx.createLinearGradient(0, 0, W, H);
    g.addColorStop(0, rank.bgTop); g.addColorStop(0.4, rank.bgBot); g.addColorStop(1, '#050508');
    ctx.fillStyle = g; ctx.fillRect(0, 0, W, H);
    var gg = ctx.createRadialGradient(cx, 100, 20, cx, 100, 250);
    gg.addColorStop(0, rank.glow); gg.addColorStop(1, 'transparent');
    ctx.fillStyle = gg; ctx.fillRect(0, 0, W, 350);
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';

    // 品牌
    ctx.fillStyle = rank.accent; ctx.font = 'bold 16px ' + F;
    ctx.fillText('\u5b89\u6735\u8033 \u00b7 \u8ba9\u7f8e\u597d\u53d1\u751f', cx, 36);
    ctx.fillStyle = 'rgba(255,255,255,0.04)'; ctx.font = '10px ' + F;
    ctx.fillText('AiRaquas \u00b7 AI \u5934\u76ae\u5065\u5eb7\u7ba1\u7406', cx, 54);
    ctx.strokeStyle = 'rgba(255,255,255,0.03)'; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(50, 66); ctx.lineTo(W-50, 66); ctx.stroke();

    // 分数圆
    var ry = 190;
    var og = ctx.createRadialGradient(cx, ry, 50, cx, ry, 120);
    og.addColorStop(0, rank.color + '22'); og.addColorStop(0.5, rank.color + '0a'); og.addColorStop(1, 'transparent');
    ctx.fillStyle = og; ctx.beginPath(); ctx.arc(cx, ry, 120, 0, Math.PI*2); ctx.fill();
    ctx.strokeStyle = rank.color + '44'; ctx.lineWidth = 2.5;
    ctx.beginPath(); ctx.arc(cx, ry, 85, 0, Math.PI*2); ctx.stroke();
    for (var a = 0; a < 12; a++) {
      var ang = (a / 12) * Math.PI * 2 - Math.PI/2;
      ctx.beginPath(); ctx.arc(cx + Math.cos(ang)*72, ry + Math.sin(ang)*72, 3, 0, Math.PI*2);
      ctx.fillStyle = rank.color + (a < 3 ? '66' : '18'); ctx.fill();
    }
    var cg = ctx.createRadialGradient(cx-10, ry-10, 5, cx, ry, 80);
    cg.addColorStop(0, rank.color + '60'); cg.addColorStop(0.6, rank.color + '20'); cg.addColorStop(1, rank.color + '05');
    ctx.beginPath(); ctx.arc(cx, ry, 78, 0, Math.PI*2); ctx.fillStyle = cg; ctx.fill();
    ctx.fillStyle = rank.color; ctx.font = 'bold 74px ' + F;
    ctx.fillText(String(stats.score), cx, ry - 4);
    ctx.fillStyle = 'rgba(255,255,255,0.12)'; ctx.font = '14px ' + F;
    ctx.fillText('\u7efc\u5408\u8bc4\u5206', cx, ry + 48);

    // 称号
    ctx.font = 'bold 28px ' + F; ctx.fillStyle = rank.color;
    ctx.fillText(rank.badge + ' ' + rank.title, cx, ry + 105);
    ctx.fillStyle = rank.color + '20'; ctx.font = '12px ' + F;
    ctx.fillText('\u51fb\u8d25\u4e86', cx - 50, ry + 142);
    ctx.font = 'bold 22px ' + F; ctx.fillStyle = rank.color;
    ctx.fillText(rank.percent + '%', cx, ry + 142);
    ctx.fillStyle = rank.color + '20'; ctx.font = '12px ' + F;
    ctx.fillText('\u7684\u7528\u6237', cx + 50, ry + 142);

    // 分隔
    var ml = ry + 172;
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.beginPath(); ctx.moveTo(40, ml); ctx.lineTo(W-40, ml); ctx.stroke();

    // 头皮类型
    ctx.fillStyle = rank.color; ctx.font = 'bold 20px ' + F;
    ctx.fillText(stats.type || '\u5065\u5eb7\u5934\u76ae', cx, ml + 30);
    ctx.fillStyle = 'rgba(255,255,255,0.08)'; ctx.font = '13px ' + F;
    ctx.fillText(rank.desc, cx, ml + 56);

    // 维度评分
    var dy0 = ml + 85;
    ctx.fillStyle = 'rgba(255,255,255,0.05)'; ctx.font = '11px ' + F; ctx.textAlign = 'left';
    ctx.fillText('\u5404\u7ef4\u5ea6\u8bc4\u5206', 50, dy0 - 5); ctx.textAlign = 'center';
    var dimLabels = ['\u6cb9\u8102\u5206\u6ccc','\u6c34\u5206\u542b\u91cf','\u53d1\u91cf\u5bc6\u5ea6','\u5934\u76ae\u5065\u5eb7'];
    var dims = stats.dimensions && stats.dimensions.length === 4
      ? stats.dimensions
      : dimLabels.map(function(l,i) { return {label:l,score:stats.score - (3-i)*6}; });
    var bx = 100, bw = 340, bh = 8, gp = 48;
    dims.forEach(function(dim, i) {
      var y = dy0 + 10 + i * gp, sc = Math.max(0, Math.min(100, dim.score || 50));
      ctx.textAlign = 'right'; ctx.fillStyle = 'rgba(255,255,255,0.3)'; ctx.font = '11px ' + F;
      ctx.fillText(dim.label, bx - 8, y + 4);
      ctx.fillStyle = rank.barBg || 'rgba(255,255,255,0.02)';
      ctx.fillRect(bx, y, bw, bh);
      var fw = (sc / 100) * bw;
      if (fw > 0) {
        var bc = sc >= 80 ? '#64c882' : sc >= 60 ? '#ffd700' : sc >= 40 ? '#ff8c42' : '#ff6b6b';
        ctx.fillStyle = bc; ctx.fillRect(bx, y, fw, bh);
      }
      ctx.textAlign = 'left';
      ctx.fillStyle = sc >= 70 ? rank.color : 'rgba(255,255,255,0.35)'; ctx.font = 'bold 13px ' + F;
      ctx.fillText(String(sc), bx + bw + 10, y + 5);
      if (sc < 50) { ctx.fillStyle = 'rgba(255,80,80,0.25)'; ctx.font = '12px ' + F; ctx.fillText('\u26a0\ufe0f', bx + bw + 40, y + 5); }
    });

    // 底部CTA
    var ty = dy0 + 10 + 4 * gp + 15;
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.beginPath(); ctx.moveTo(40, ty); ctx.lineTo(W-40, ty); ctx.stroke();
    ctx.textAlign = 'center';
    var wd = dims.reduce(function(a,b) { return a.score < b.score ? a : b; }, dims[0]);
    if (wd && wd.score < 70) {
      ctx.fillStyle = rank.color + '50'; ctx.font = 'bold 14px ' + F;
      ctx.fillText('\ud83d\udd04 \u91cd\u70b9\u5173\u6ce8: ' + wd.label + ' (' + wd.score + '\u5206)', cx, ty + 25);
    }
    var st = stats.tips && stats.tips[0] ? stats.tips[0].substring(0, 28) : rank.desc;
    ctx.fillStyle = 'rgba(255,255,255,0.06)'; ctx.font = '12px ' + F;
    ctx.fillText('\ud83d\udca1 ' + st + (st.length >= 28 ? '...' : ''), cx, ty + 48);

    // QR区
    var qy = ty + 80;
    ctx.strokeStyle = 'rgba(255,255,255,0.025)';
    ctx.beginPath(); ctx.moveTo(30, qy - 5); ctx.lineTo(W-30, qy - 5); ctx.stroke();
    ctx.fillStyle = rank.color; ctx.font = 'bold 19px ' + F;
    ctx.fillText('\u626b\u7801\u514d\u8d39\u68c0\u6d4b\u4f60\u7684\u5934\u76ae\u5065\u5eb7', cx, qy + 25);
    ctx.fillStyle = 'rgba(255,255,255,0.06)'; ctx.font = '11px ' + F;
    ctx.fillText('AI \u667a\u80fd\u5206\u6790 \u00b7 3\u79d2\u51fa\u62a5\u544a \u00b7 \u5168\u7f51\u4ea7\u54c1\u63a8\u8350', cx, qy + 48);

    // QR码（通过 QR Server API 生成，异步加载后重绘）
    ctx.fillStyle = rank.color + '30'; ctx.font = 'bold 14px ' + F;
    ctx.fillText('\ud83d\udcf1 airaquas.hair', cx, qy + 110);

    ctx.fillStyle = 'rgba(255,255,255,0.03)'; ctx.font = '10px ' + F;
    ctx.fillText('airaquas.hair', cx, H - 20);

    // 同步生成PNG
    var dataUrl = cv.toDataURL('image/png');

    posterPreview.src = dataUrl;
    posterModal.classList.add('active');

    // 异步加载QR码后重绘预览（下载始终使用最新的src）
    var qrUrl = 'https://api.qrserver.com/v1/create-qr-code/?size=130x130&data=https://airaquas.hair&bgcolor=0d0d1a&color=' + rank.color.replace('#','');
    (function(url) {
      var qi = new Image(); qi.crossOrigin = 'anonymous';
      qi.onload = function() {
        try {
          var ctx2 = cv.getContext('2d');
          ctx2.drawImage(qi, cx - 65, qy + 65, 130, 130);
          posterPreview._qready = 1;
          posterPreview.src = cv.toDataURL('image/png');
        } catch(e) {}
      };
      qi.onerror = function() { posterPreview._qready = 1; }; // QR加载失败也不阻塞下载
      qi.src = url;
    })(qrUrl);

    // 自动下载（若QR未加载完，给3秒缓冲）
    (function() {
      var already = false;
      var dl = function() {
        if (already) return; already = true;
        try {
          var a = document.createElement('a');
          a.download = 'AiRaquas_' + stats.score + 'fen_' + new Date().toISOString().slice(0,10) + '.png';
          a.href = posterPreview.src;
          document.body.appendChild(a); a.click(); document.body.removeChild(a);
        } catch(e) {}
      };
      // 如果QR已加载或3秒后，触发下载
      if (posterPreview._qready) { dl(); return; }
      var iv = setInterval(function() {
        if (posterPreview._qready) { clearInterval(iv); dl(); }
      }, 200);
      setTimeout(function() { clearInterval(iv); if (!already) dl(); }, 3000);
    })();

    return dataUrl;
  } catch(e) {
    showToast('\u751f\u6210\u5931\u8d25: ' + e.message);
    return null;
  } finally {
  }
}

function closePoster() {
  if (posterModal) posterModal.classList.remove('active');
}

function downloadPoster() {
  if (!posterPreview || !posterPreview.src) { showToast('请先生成海报'); return; }
  const a = document.createElement('a');
  a.download = 'AiRaquas_头皮健康_' + new Date().toISOString().slice(0,10) + '.png';
  a.href = posterPreview.src;
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  showToast('✅ 海报已保存！');
}

/* 跨浏览器剪贴板复制（兼容 Safari / Firefox 老旧版本） */
async function copyToClipboard(text) {
  // 优先使用 Clipboard API（需要 HTTPS 或 localhost）
  if (navigator.clipboard && navigator.clipboard.writeText) {
    try { await navigator.clipboard.writeText(text); return; } catch(e) {}
  }
  // fallback: 使用 textarea
  try {
    var ta = document.createElement('textarea');
    ta.value = text; ta.style.cssText = 'position:fixed;left:-9999px;opacity:0';
    document.body.appendChild(ta); ta.focus(); ta.select();
    document.execCommand('copy');
    document.body.removeChild(ta);
    return;
  } catch(e) {
    throw new Error('复制失败');
  }
}

async function doShare() {
  const stats = getCurrentReportStats();
  const rank = getRankInfo(stats.score);
  const t = '🔥 我的头皮健康分 ' + stats.score + ' 分！' + rank.badge + rank.title + ' 击败了 ' + rank.percent + '% 的用户！快来安柯耳测测你的头皮健康吧';
  if (navigator.share) {
    try { navigator.share({ title: '安柯耳 airaquas.hair AI头皮健康检测', text: t }); return; } catch(e) {}
  }
  try { await copyToClipboard(t + '\nhttps://airaquas.hair'); showToast('✅ 文案已复制！'); }
  catch { showToast('💡 截图分享给好友'); }
}


