// ── CHECK-IN ──
let streak = 0;
const checkinBtn = document.getElementById('checkinBtn');
const streakEl = document.getElementById('streak');
if(localStorage.getItem('checkinDate') === new Date().toDateString()){
  checkinBtn.classList.add('checked');
  checkinBtn.innerHTML = '☀️ 已签到 ' + streakEl.outerHTML;
  streak = parseInt(localStorage.getItem('streak') || 0);
} else {
  let prev = localStorage.getItem('checkinDate');
  if(prev && new Date(prev).getTime() === new Date().getTime() - 86400000) {
    streak = parseInt(localStorage.getItem('streak') || 0);
  }
  streakEl.textContent = '🔥 ' + streak + ' 天';
}
checkinBtn.addEventListener('click', function(){
  if(!this.classList.contains('checked')){
    streak++;
    localStorage.setItem('streak', streak);
    localStorage.setItem('checkinDate', new Date().toDateString());
    this.classList.add('checked');
    this.innerHTML = '☀️ 已签到 <span class="streak" id="streak">🔥 ' + streak + ' 天</span>';
  }
});

